# fix-hero-bg-mobile-crop.ps1
# Root cause: 100vh mobile viewport is far narrower/taller than typical landscape hero
# photos, so object-fit:cover cropped away most of the image regardless of object-position.
# Fix: blurred full-bleed backdrop + contain-fit sharp image below 640px (no cropping),
# desktop untouched (still cover, unaffected since backdrop stays fully hidden behind it).
$ErrorActionPreference = 'Stop'
Write-Host "Applying Hero mobile background fix..." -ForegroundColor Cyan

Write-Host "Writing src\components\public\HeroSection.tsx"
$dir = Split-Path -Parent "src\components\public\HeroSection.tsx"
if ($dir -and !(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
$b64HeroSection = @"

"@
[System.IO.File]::WriteAllBytes("src\components\public\HeroSection.tsx", [System.Convert]::FromBase64String($b64HeroSection))

Write-Host "Done. 1 file updated." -ForegroundColor Green